tinymce.PluginManager.add('images', function(editor, url) {
    //  editor.ui.registry.addIcon('stream', '<svg class="icon"><use xlink:href="../../svg/custom-icons.svg#stream"></use></svg>');
    // editor.ui.registry.addIcon('stream', '<svg width="24" height="24"><use xlink:href="../../tinymce/svg/custom-icons.svg#stream"></use></svg>');
    editor.ui.registry.addIcon('images', '<?xml version="1.0" encoding="UTF-8"?>\n' +
        '<svg width="24px" height="24px" viewBox="0 0 24 24" version="1.1" xmlns="http://www.w3.org/2000/svg" xmlns:xlink="http://www.w3.org/1999/xlink">\n' +
        '    <defs></defs>\n' +
        '    <g stroke="none" stroke-width="1" fill="none" fill-rule="evenodd">\n' +
        '        <path d="M5,15.7393398 L8.26966991,12.4696699 C8.56256313,12.1767767 9.03743687,12.1767767 9.33033009,12.4696699 L11.9,15.0393398 L16.0030032,10.9363366 C16.2958965,10.6434434 16.7707702,10.6434434 17.0636634,10.9363366 L19,12.8726732 L19,5 L5,5 L5,15.7393398 Z M5,17.8606602 L5,19 L7.93933983,19 L10.8393398,16.1 L8.8,14.0606602 L5,17.8606602 Z M19,14.9939935 L16.5333333,12.5273268 L10.0606602,19 L19,19 L19,14.9939935 Z M4,3 L20,3 C20.5522847,3 21,3.44771525 21,4 L21,20 C21,20.5522847 20.5522847,21 20,21 L4,21 C3.44771525,21 3,20.5522847 3,20 L3,4 C3,3.44771525 3.44771525,3 4,3 Z M10,11 C11.1045695,11 12,10.1045695 12,9 C12,7.8954305 11.1045695,7 10,7 C8.8954305,7 8,7.8954305 8,9 C8,10.1045695 8.8954305,11 10,11 Z" fill="#000000" fill-rule="nonzero"></path>\n' +
        '    </g>\n' +
        '</svg>');

    var openDialog = function () {
        var cid = editor.getParam('content_id');
        var ctype = editor.getParam('content_type');
        var module_code = editor.getParam('module_code');
        var query = '?cid='+cid+'&ctype='+ctype+'&moduleCode='+module_code;
        return editor.windowManager.openUrl({
            url: tinymce.baseURL + '/plugins/images/scripts/image.php'+query,
            title: 'Image',
            width: 840,
            height: 465,

        });

    };


    editor.ui.registry.addButton('images', {
        tooltip: 'Image',
        icon: 'images',
        onAction: function () {
            // Open window
            openDialog();
        }

    });

    // Adds a menu item, which can then be included in any menu via the menu/menubar configuration
    editor.ui.registry.addMenuItem('images', {
        text: 'Image',
        icon: 'images',
        onAction: function () {
            // Open window
            openDialog();
        }
    });
});